hook.command:
.claude/hooks/pyrun -c "
import json, sys, os
d = json.load(sys.stdin)
ti = d.get('tool_input', {})
p = ti.get('file_path', '')
if not p or not p.endswith(('.ts', '.tsx')):
    sys.exit(0)
skip = ['node_modules', '.spec.', '.test.', '__tests__', '.d.ts']
if any(s in p for s in skip):
    sys.exit(0)
if not os.path.exists(p):
    sys.exit(0)
with open(p) as f:
    lines = len(f.readlines())
limits = {
    '.service.ts': (300, 450),
    '.controller.ts': (200, 350),
    '.repository.ts': (300, 450),
    '.module.ts': (100, 200),
}
for suffix, (soft, hard) in limits.items():
    if p.endswith(suffix):
        if lines > hard:
            print(json.dumps({'decision': 'block', 'reason': f'[SIZE] BLOCKED: {os.path.basename(p)} is {lines} lines (hard limit: {hard}). Extract before continuing.'}))
            sys.exit(2)
        elif lines > soft:
            print(json.dumps({'systemMessage': f'[SIZE] {os.path.basename(p)} is {lines} lines (soft limit: {soft}). Consider extraction.'}))
        break
sys.exit(0)
"
